```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Convert records to the appropriate format for sqlgen
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id_str,
                               const std::string& col_name,
                               const std::optional<std::string>& new_value) {
  // Determine the table type based on table name
  auto table_type = get_table_type(table_name);

  // Convert record_id to appropriate type
  auto record_id = convert_to_primary_key_type(record_id_str, table_type);

  // Create the update statement
  auto update_stmt = sqlgen::update(table_type) | 
                   sqlgen::set(get_column_by_name(col_name, table_type)) |
                   sqlgen::where(get_primary_key_column(table_type) == record_id);

  // Connect to the database and execute
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  auto result = update_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to modify record");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id_str) {
  // Determine the table type based on table name
  auto table_type = get_table_type(table_name);

  // Convert record_id to appropriate type
  auto record_id = convert_to_primary_key_type(record_id_str, table_type);

  // Create the delete statement
  auto delete_stmt = sqlgen::delete_from<table_type> | 
                   sqlgen::where(get_primary_key_column(table_type) == record_id);

  // Connect to the database and execute
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  auto result = delete_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}

// Helper functions (implementation details)
inline auto get_table_type(const std::string& table_name) {
  // This would typically be a mapping from table name to actual struct type
  // For simplicity, we'll assume the table name matches the struct name
  if (table_name == "Student") return Student;
  if (table_name == "Course") return Course;
  if (table_name == "Score") return Score;
  if (table_name == "Major") return Major;
  throw std::invalid_argument("Invalid table name");
}

template<typename T>
auto get_primary_key_column() {
  // Extract the primary key column from the struct
  using PrimaryKeyT = sqlgen::PrimaryKeyType<T>;
  if constexpr (std::is_same_v<PrimaryKeyT, sqlgen::PrimaryKey<sqlgen::Varchar<10>>) {
    return &T::SNo;
  } else if constexpr (std::is_same_v<PrimaryKeyT, sqlgen::PrimaryKey<uint32_t>>) {
    return &T::CID;
  }
  throw std::logic_error("Unsupported primary key type");
}

template<typename T>
auto get_column_by_name(const std::string& col_name) {
  // This would typically use reflection to find the column by name
  // For simplicity, we'll assume the column name matches the field name
  if (col_name == "SNo") return &T::SNo;
  if (col_name == "SName") return &T::SName;
  if (col_name == "Sex") return &T::Sex;
  if (col_name == "Birthday") return &T::Birthday;
  if (col_name == "Major") return &T::Major;
  if (col_name == "CName") return &T::CName;
  if (col_name == "Term") return &T::Term;
  if (col_name == "CTime") return &T::CTime;
  if (col_name == "Credit") return &T::Credit;
  if (col_name == "ScID") return &T::ScID;
  if (col_name == "Score") return &T::Score;
  if (col_name == "MName") return &T::MName;
  throw std::invalid_argument("Invalid column name");
}

template<typename T>
auto convert_to_primary_key_type(const std::string& value, 
                                const T& table_type) {
  using PrimaryKeyT = sqlgen::PrimaryKeyType<T>;
  if constexpr (std::is_same_v<PrimaryKeyT, sqlgen::PrimaryKey<sqlgen::Varchar<10>>) {
    return sqlgen::Varchar<10>(value);
  } else if constexpr (std::is_same_v<PrimaryKeyT, sqlgen::PrimaryKey<uint32_t>>) {
    return std::stoi(value);
  }
  throw std::logic_error("Unsupported primary key type");
}
```

**Explanation of the implementation:**

1. **`add_eas_records`**: Uses `sqlgen::insert` to insert records into the database. The function connects to the database and handles the insertion operation.

2. **`modify_eas_records_by_id`**: 
   - Determines the appropriate table type based on the table name
   - Converts the record ID to the correct type using `convert_to_primary_key_type`
   - Creates an update statement using `sqlgen::update` with the specified column and new value
   - Executes the update operation

3. **`delete_eas_records_by_id`**:
   - Determines the appropriate table type
   - Converts the record ID to the correct type
   - Creates a delete statement using `sqlgen::delete_from` with the primary key condition
   - Executes the delete operation

The implementation uses the sqlgen library's fluent API for building SQL statements and follows the patterns shown in the reference materials. Error handling is included through exception throwing for failed operations.

