    auto where_conditions = std::make_optional<sqlgen::Condition<sqlgen::Nothing>>();

    if (filters.title_keyword) {
        auto title_condition = "title"_c.like(filters.title_keyword.value());
        where_conditions = where_conditions && title_condition;
    }

    if (filters.min_year) {
        auto year_condition = "year"_c >= filters.min_year.value();
        where_conditions = where_conditions && year_condition;
    }

    if (filters.genre) {
        auto genre_condition = "genre"_c == filters.genre.value();
        where_conditions = where_conditions && genre_condition;
