#include <vector>

namespace create_view_order_summary {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  static constexpr const char* tablename = "OrderSummaryView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
    using namespace sqlgen::literals;

    // 1. Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Create the view using CREATE VIEW AS with SELECT statement
    auto select_stmt = sqlgen::select_from<Order, "o">(
        "order_id"_t1, 
        "customer"_t1, 
        ("unit_price"_t2 * "quantity"_t2).sum().as<"total">()
    ) | sqlgen::inner_join<OrderItem, "oi">("order_id"_t1 == "order_id"_t2)
      | sqlgen::group_by("order_id"_t1, "customer"_t1);

    auto create_view = sqlgen::create_as<OrderSummary>(select_stmt);
    conn->execute(sqlgen::sqlite::to_sql(create_view));

    // 3. Read the view using select_from
    auto read_stmt = sqlgen::select_from<OrderSummary>();
    auto result = conn->read<std::vector<OrderSummary>>(read_stmt);

    // 4. Return the verification results
    return result.value();
}

}  // namespace create_view_order_summary

